function AccordionItem({ faq, index }: { faq: any, index: number }) {
    const [isOpen, setIsOpen] = useState(false);

    return (
        <motion.div 
            initial={{ opacity: 0, y: 20 }}
            whileInView={{ opacity: 1, y: 0 }}
            viewport={{ once: true }}
            transition={{ duration: 0.5, delay: index * 0.1 }}
            className="glass-card"
            style={{ padding: '0', overflow: 'hidden' }}
        >
            <button 
                onClick={() => setIsOpen(!isOpen)}
                style={{ 
                    width: '100%', 
                    padding: '1.5rem 2rem', 
                    textAlign: 'left', 
                    background: 'none', 
                    border: 'none', 
                    display: 'flex', 
                    justifyContent: 'space-between', 
                    alignItems: 'center',
                    cursor: 'pointer'
                }}
            >
                <h3 style={{ fontSize: '1.2rem', color: 'var(--text-primary)', margin: 0, fontWeight: 600 }}>{faq.q}</h3>
                <span style={{ 
                    fontSize: '1.5rem', 
                    color: 'var(--accent-primary)',
                    transform: isOpen ? 'rotate(45deg)' : 'none',
                    transition: 'transform 0.3s ease'
                }}>
                    +
                </span>
            </button>
            <AnimatePresence>
                {isOpen && (
                    <motion.div
                        initial={{ height: 0, opacity: 0 }}
                        animate={{ height: 'auto', opacity: 1 }}
                        exit={{ height: 0, opacity: 0 }}
                        transition={{ duration: 0.3 }}
                    >
                        <div style={{ padding: '0 2rem 1.5rem 2rem', color: 'var(--text-secondary)', lineHeight: 1.6 }}>
                            {faq.a}
                        </div>
                    </motion.div>
                )}
            </AnimatePresence>
        </motion.div>
    );
}
