        "+                <span style={{ ",
        "+                    fontSize: '1.5rem', ",
        "+                    color: 'var(--accent-primary)',",
        "+                    transform: isOpen ? 'rotate(45deg)' : 'none',",
        "+                    transition: 'transform 0.3s ease'",
        "+                }}>",
        "+                    +",
        "+                </span>",
        "+            </button>",
        "+            <AnimatePresence>",
